1	<?php
2	// Application route definitions
3	use think\facade\Route;
4	
5	// === Slice 1: Foundation ===
6	Route::get('health', 'Health/index');
7	Route::get('/', function () {
8	    return redirect('/static/index.html');
9	});
10	
11	// === Slice 2: Auth and Identity ===
12	Route::get('auth/captcha', 'Captcha/generate');
13	Route::post('auth/register', 'Auth/register');
14	Route::post('auth/login', 'Auth/login');
15	Route::post('auth/logout', 'Auth/logout')->middleware('authCheck');
16	Route::get('auth/me', 'Auth/me')->middleware('authCheck');
17	Route::post('auth/mfa/enroll', 'Auth/mfaEnroll')->middleware('authCheck', 'system_admin');
18	Route::post('auth/mfa/verify', 'Auth/mfaVerify')->middleware('authCheck', 'system_admin');
19	
20	// Issue I-09: admin-only user-creation endpoint. The public /auth/register
21	// refuses to mint system_admin; this authenticated path is the only way to
22	// bootstrap additional admin accounts.
23	Route::post('admin/users', 'Auth/adminCreateUser')->middleware('authCheck', 'system_admin')->completeMatch(true);
24	
25	// === Slice 3: Profiles, Verification, Scope ===
26	
27	// Entity profiles: specific routes BEFORE general list (order matters)
28	Route::get('entities/field-definitions', 'Entity/fieldDefinitions')->middleware('authCheck')->completeMatch(true);
29	Route::post('entities/:id/merge', 'Entity/merge')->middleware('authCheck')->pattern(['id' => '\d+']);
30	Route::get('entities/:id', 'Entity/read')->middleware('authCheck')->pattern(['id' => '\d+']);
31	Route::patch('entities/:id', 'Entity/update')->middleware('authCheck')->pattern(['id' => '\d+']);
32	Route::get('entities', 'Entity/index')->middleware('authCheck')->completeMatch(true);
33	Route::post('entities', 'Entity/create')->middleware('authCheck')->completeMatch(true);
34	
35	// Verification - specific routes first
36	Route::post('admin/verifications/:id/approve', 'Verification/approve')->middleware('authCheck', 'system_admin')->pattern(['id' => '\d+']);
37	Route::post('admin/verifications/:id/reject', 'Verification/reject')->middleware('authCheck', 'system_admin')->pattern(['id' => '\d+']);
38	// User-facing: check own verification status (must precede generic GET /verifications)
39	Route::get('verifications/mine', 'Verification/mine')->middleware('authCheck')->completeMatch(true);
40	Route::post('verifications', 'Verification/submit')->middleware('authCheck')->completeMatch(true);
41	Route::get('verifications', 'Verification/index')->middleware('authCheck', 'system_admin')->completeMatch(true);
42	
43	// === Slice 4: Contracts and Invoices ===
44	Route::get('contracts/:id', 'Contract/read')->middleware('authCheck')->pattern(['id' => '\d+']);
45	Route::get('contracts', 'Contract/index')->middleware('authCheck')->completeMatch(true);
46	Route::post('contracts', 'Contract/create')->middleware('authCheck')->completeMatch(true);
47	
48	Route::get('invoices/:id/receipt', 'Payment/receipt')->middleware('authCheck')->pattern(['id' => '\d+']);
49	Route::get('invoices/:id', 'Invoice/read')->middleware('authCheck')->pattern(['id' => '\d+']);
50	Route::get('invoices', 'Invoice/index')->middleware('authCheck')->completeMatch(true);
51	
52	// === Slice 5: Payments, Refunds, Exports ===
53	Route::post('payments', 'Payment/create')->middleware('authCheck')->completeMatch(true);
54	Route::post('refunds', 'Payment/refund')->middleware('authCheck')->completeMatch(true);
55	Route::get('exports/ledger', 'Payment/ledger')->middleware('authCheck');
56	Route::get('exports/reconciliation', 'Payment/reconciliation')->middleware('authCheck');
57	
58	// === Slice 6: Messaging and Risk ===
59	Route::get('conversations/:id/messages', 'Message/messages')->middleware('authCheck')->pattern(['id' => '\d+']);
60	Route::get('conversations', 'Message/conversations')->middleware('authCheck')->completeMatch(true);
61	Route::post('conversations', 'Message/createConversation')->middleware('authCheck')->completeMatch(true);
62	// Issue I-12: pre-send risk check — advisory evaluation, no persistence.
63	// Must come BEFORE the generic POST /messages route so it takes precedence.
64	Route::post('messages/preflight-risk', 'Message/preflightRisk')->middleware('authCheck')->completeMatch(true);
65	Route::post('messages', 'Message/send')->middleware('authCheck')->completeMatch(true);
66	Route::patch('messages/:id/recall', 'Message/recall')->middleware('authCheck')->pattern(['id' => '\d+']);
67	Route::post('messages/:id/report', 'Message/report')->middleware('authCheck')->pattern(['id' => '\d+']);
68	
69	// Admin risk keyword management
70	Route::get('admin/risk-keywords', 'Message/riskKeywords')->middleware('authCheck', 'system_admin');
71	Route::post('admin/risk-keywords', 'Message/createRiskKeyword')->middleware('authCheck', 'system_admin')->completeMatch(true);
72	Route::patch('admin/risk-keywords/:id', 'Message/updateRiskKeyword')->middleware('authCheck', 'system_admin')->pattern(['id' => '\d+']);
73	Route::delete('admin/risk-keywords/:id', 'Message/deleteRiskKeyword')->middleware('authCheck', 'system_admin')->pattern(['id' => '\d+']);
74	
75	// === Slice 7: Audit ===
76	Route::get('audit-logs', 'Audit/index')->middleware('authCheck', 'system_admin')->completeMatch(true);
77	
78	// === Delegation workflow (county_admin two-person rule) ===
79	Route::post('delegations/:id/approve', 'Delegation/approve')->middleware('authCheck', 'system_admin')->pattern(['id' => '\d+']);
80	Route::get('delegations', 'Delegation/index')->middleware('authCheck', 'system_admin')->completeMatch(true);
81	Route::post('delegations', 'Delegation/create')->middleware('authCheck', 'system_admin')->completeMatch(true);
82	
83	// === Slice 8: Admin, Jobs, Config, API Docs ===
84	Route::get('api/docs', 'Admin/apiDocs');
85	Route::get('admin/jobs', 'Admin/listJobs')->middleware('authCheck', 'system_admin');
86	Route::post('admin/jobs/run', 'Admin/runJobs')->middleware('authCheck', 'system_admin');
87	Route::get('admin/config', 'Admin/getConfig')->middleware('authCheck', 'system_admin');
88	Route::patch('admin/config/:key', 'Admin/updateConfig')->middleware('authCheck', 'system_admin');
