4	namespace app\service;
5	
6	use think\facade\Db;
7	
8	class RefundService
9	{
10	    public static function create(array $data, array $user, string $traceId = ''): array
11	    {
12	        $invoiceId = (int)($data['invoice_id'] ?? 0);
13	        $amountCents = (int)($data['amount_cents'] ?? 0);
14	        $reason = trim($data['reason'] ?? '');
15	
16	        if ($invoiceId <= 0) throw new \think\exception\HttpException(400, 'invoice_id is required');
17	        if ($amountCents <= 0) throw new \think\exception\HttpException(400, 'amount_cents must be positive');
18	        if (empty($reason)) throw new \think\exception\HttpException(400, 'reason is required');
19	
20	        $invoice = Db::table('invoices')->where('id', $invoiceId)->find();
21	        if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
22	
23	        $contract = Db::table('contracts')->where('id', $invoice['contract_id'])->find();
24	        if (!$contract || !ScopeService::canAccess($user, $contract['geo_scope_level'], (int)$contract['geo_scope_id'])) {
25	            throw new \think\exception\HttpException(403, 'Outside your scope');
26	        }
27	
28	        $beforeBalance = (int)$invoice['amount_cents'] - (int)Db::table('refunds')->where('invoice_id', $invoiceId)->sum('amount_cents');
29	
30	        $refundId = Db::table('refunds')->insertGetId([
31	            'invoice_id'  => $invoiceId,
32	            'amount_cents' => $amountCents,
33	            'reason'      => $reason,
34	            'issued_by'   => $user['id'],
35	        ]);
36	
37	        $totalRefunded = (int)Db::table('refunds')->where('invoice_id', $invoiceId)->sum('amount_cents');
38	        $balanceCents = (int)$invoice['amount_cents'] - $totalRefunded;
39	
40	        LogService::info('refund_issued', ['refund_id' => $refundId, 'invoice_id' => $invoiceId], $traceId);
41	
42	        // Append-only audit (prompt: refund actions with before/after balance)
43	        AuditService::log(
44	            'refund_issued',
45	            (int)$user['id'],
46	            'invoice',
47	            $invoiceId,
48	            ['balance_cents' => $beforeBalance],
49	            ['refund_id' => $refundId, 'amount_cents' => $amountCents, 'reason' => $reason, 'balance_cents' => max($balanceCents, 0)],
50	            RequestContext::ip(),
51	            RequestContext::device(),
52	            $traceId
53	        );
54	
55	        return ['refund_id' => $refundId, 'invoice_balance_cents' => max($balanceCents, 0)];
56	    }
57	}
