4	namespace app\service;
5	
6	use think\facade\Db;
7	
8	/**
9	 * Contract CRUD and billing schedule generation.
10	 * On creation, generates all invoices for the full contract term.
11	 */
12	class ContractService
13	{
14	    public static function create(array $data, array $user, string $traceId = ''): array
15	    {
16	        $profileId = (int)($data['profile_id'] ?? 0);
17	        $startDate = $data['start_date'] ?? '';
18	        $endDate = $data['end_date'] ?? '';
19	        $rentCents = (int)($data['rent_cents'] ?? 0);
20	        $depositCents = (int)($data['deposit_cents'] ?? 0);
21	        $maintenanceCents = (int)($data['maintenance_cents'] ?? 0);
22	        $frequency = $data['frequency'] ?? 'monthly';
23	
24	        if ($profileId <= 0) throw new \think\exception\HttpException(400, 'profile_id is required');
25	        if (empty($startDate) || empty($endDate)) throw new \think\exception\HttpException(400, 'start_date and end_date are required');
26	        if ($rentCents <= 0) throw new \think\exception\HttpException(400, 'rent_cents must be positive');
27	        if (!in_array($frequency, ['monthly', 'quarterly', 'yearly'], true)) {
28	            throw new \think\exception\HttpException(400, 'frequency must be monthly, quarterly, or yearly');
29	        }
30	
31	        $start = new \DateTime($startDate);
32	        $end = new \DateTime($endDate);
33	        if ($end <= $start) throw new \think\exception\HttpException(400, 'end_date must be after start_date');
34	
35	        // Verify profile exists and scope access
36	        $profile = Db::table('entity_profiles')->where('id', $profileId)->find();
37	        if (!$profile) throw new \think\exception\HttpException(404, 'Profile not found');
38	        if (!ScopeService::canAccess($user, $profile['geo_scope_level'], (int)$profile['geo_scope_id'])) {
39	            throw new \think\exception\HttpException(403, 'Profile outside your scope');
40	        }
41	
42	        $contractId = Db::table('contracts')->insertGetId([
43	            'profile_id'       => $profileId,
44	            'start_date'       => $startDate,
45	            'end_date'         => $endDate,
46	            'rent_cents'       => $rentCents,
47	            'deposit_cents'    => $depositCents,
48	            'maintenance_cents'=> $maintenanceCents,
49	            'frequency'        => $frequency,
50	            'status'           => 'active',
51	            'geo_scope_level'  => $user['geo_scope_level'],
52	            'geo_scope_id'     => $user['geo_scope_id'],
53	            'created_by'       => $user['id'],
54	        ]);
55	
56	        // Generate billing schedule
57	        $invoiceCount = self::generateSchedule($contractId, $start, $end, $rentCents + $maintenanceCents, $frequency);
58	
59	        LogService::info('contract_created', [
60	            'contract_id' => $contractId,
61	            'invoices'    => $invoiceCount,
62	        ], $traceId);
63	
64	        // Append-only audit (prompt: contract edits / bill generation tracked)
65	        AuditService::log(
66	            'contract_created',
67	            (int)$user['id'],
68	            'contract',
69	            (int)$contractId,
70	            null,
71	            [
72	                'profile_id'   => $profileId,
73	                'start_date'   => $startDate,
74	                'end_date'     => $endDate,
75	                'rent_cents'   => $rentCents,
76	                'deposit_cents'=> $depositCents,
77	                'frequency'    => $frequency,
78	                'invoices_created' => $invoiceCount,
79	            ],
80	            RequestContext::ip(),
81	            RequestContext::device(),
82	            $traceId
83	        );
84	
85	        return ['contract_id' => $contractId, 'invoices_created' => $invoiceCount];
86	    }
