108	        if (!$contract) throw new \think\exception\HttpException(404, 'Contract not found');
109	        if (!ScopeService::canAccess($user, $contract['geo_scope_level'], (int)$contract['geo_scope_id'])) {
110	            throw new \think\exception\HttpException(403, 'Contract outside your scope');
111	        }
