118	    /**
119	     * Generate all invoices for the contract term.
120	     */
121	    private static function generateSchedule(int $contractId, \DateTime $start, \DateTime $end, int $periodAmountCents, string $frequency): int
122	    {
123	        $interval = match ($frequency) {
124	            'monthly'   => new \DateInterval('P1M'),
125	            'quarterly' => new \DateInterval('P3M'),
126	            'yearly'    => new \DateInterval('P1Y'),
127	        };
128	
129	        $count = 0;
130	        $current = clone $start;
131	        while ($current < $end) {
132	            $dueDate = clone $current;
133	            $dueDate->add($interval); // Due at end of period
134	            if ($dueDate > $end) $dueDate = clone $end;
135	
136	            $invoiceId = Db::table('invoices')->insertGetId([
137	                'contract_id'  => $contractId,
138	                'due_date'     => $dueDate->format('Y-m-d'),
139	                'amount_cents' => $periodAmountCents,
140	                'status'       => 'unpaid',
141	            ]);
142	
143	            // Create initial snapshot
144	            InvoiceService::createSnapshot($invoiceId);
145	
146	            $current->add($interval);
147	            $count++;
148	        }
149	
150	        return $count;
151	    }
152	}
