69	        if (!$invoice) throw new \think\exception\HttpException(404, 'Invoice not found');
70	
71	        $current = $invoice['status'];
72	        $allowed = self::VALID_TRANSITIONS[$current] ?? [];
73	        if (!in_array($newStatus, $allowed, true)) {
74	            throw new \think\exception\HttpException(409,
75	                "Invalid invoice transition from '{$current}' to '{$newStatus}'"
76	            );
77	        }
78	
79	        $newVersion = (int)$invoice['snapshot_version'] + 1;
80	        Db::table('invoices')->where('id', $invoiceId)->update([
81	            'status'           => $newStatus,
82	            'snapshot_version' => $newVersion,
83	        ]);
