135	    /**
136	     * Idempotent late-fee recalculation for all overdue invoices.
137	     * Safe to call on every scheduler tick — overwrites late_fee_cents with the
138	     * correct value for today; no accumulation or drift.
139	     */
140	    public static function updateLateFees(string $asOfDate, string $traceId = ''): int
141	    {
142	        $overdueInvoices = Db::table('invoices')
143	            ->where('status', 'overdue')
144	            ->select()
145	            ->toArray();
146	
147	        $updated = 0;
148	        foreach ($overdueInvoices as $inv) {
149	            $daysOverdue = max(0, (int)((strtotime($asOfDate) - strtotime($inv['due_date'])) / 86400));
150	            $lateFee = LateFeeService::calculate((int)$inv['amount_cents'], $daysOverdue);
151	            if ((int)$inv['late_fee_cents'] !== $lateFee) {
152	                Db::table('invoices')->where('id', $inv['id'])->update(['late_fee_cents' => $lateFee]);
153	                $updated++;
154	            }
155	        }
156	
157	        if ($updated > 0) {
158	            LogService::info('late_fees_updated', ['count' => $updated, 'as_of' => $asOfDate], $traceId);
159	        }
160	        return $updated;
161	    }
