4	namespace app\service;
5	
6	use think\facade\Db;
7	
8	/**
9	 * Access delegation workflow.
10	 * - Only county_admin (system_admin) can grant delegations.
11	 * - Requires approval from a SECOND county_admin (two-person rule).
12	 * - Expiry is mandatory and capped at 30 days from creation.
13	 * - On expiry, delegations are auto-revoked by the scheduled job.
14	 */
15	class DelegationService
16	{
17	    private const MAX_EXPIRY_DAYS = 30;
18	    private const VALID_SCOPES = ['village', 'township', 'county'];
19	
20	    /**
21	     * Create a pending delegation grant.
22	     * @throws \think\exception\HttpException
23	     */
24	    public static function create(array $data, array $grantor, string $traceId = '', string $ip = ''): array
25	    {
26	        if ($grantor['role'] !== 'system_admin') {
27	            throw new \think\exception\HttpException(403, 'Only system_admin may grant delegations');
28	        }
29	
30	        $granteeId = (int)($data['grantee_id'] ?? 0);
31	        $scopeLevel = $data['scope_level'] ?? '';
32	        $scopeId = (int)($data['scope_id'] ?? 0);
33	        $expiresAt = $data['expires_at'] ?? '';
34	
35	        if ($granteeId <= 0) throw new \think\exception\HttpException(400, 'grantee_id is required');
36	        if (!in_array($scopeLevel, self::VALID_SCOPES, true)) {
37	            throw new \think\exception\HttpException(400, 'scope_level must be village/township/county');
38	        }
39	        if ($scopeId <= 0) throw new \think\exception\HttpException(400, 'scope_id is required');
40	        if (empty($expiresAt)) throw new \think\exception\HttpException(400, 'expires_at is required');
41	
42	        $expiresTs = strtotime($expiresAt);
43	        if ($expiresTs === false || $expiresTs <= time()) {
44	            throw new \think\exception\HttpException(400, 'expires_at must be in the future');
45	        }
46	
47	        // Enforce 30-day cap
48	        $maxTs = time() + self::MAX_EXPIRY_DAYS * 86400;
49	        if ($expiresTs > $maxTs) {
50	            throw new \think\exception\HttpException(400,
51	                'expires_at exceeds maximum delegation window of ' . self::MAX_EXPIRY_DAYS . ' days'
52	            );
53	        }
54	
55	        // Grantee must exist and be an admin (two-person rule requires admin-to-admin)
56	        $grantee = Db::table('users')->where('id', $granteeId)->find();
57	        if (!$grantee) throw new \think\exception\HttpException(404, 'Grantee not found');
58	        if ($grantee['id'] == $grantor['id']) {
59	            throw new \think\exception\HttpException(400, 'Cannot delegate to yourself');
60	        }
61	        if ($grantee['role'] !== 'system_admin') {
62	            // Policy: delegations are strictly admin-to-admin. A farmer /
63	            // enterprise / collective user cannot receive a delegation.
64	            throw new \think\exception\HttpException(400, 'Grantee must be a system_admin');
65	        }
66	
67	        // Scope target must exist in geo_areas
68	        $geoArea = Db::table('geo_areas')->where('id', $scopeId)->find();
69	        if (!$geoArea) throw new \think\exception\HttpException(404, 'Scope target area not found');
70	
71	        $id = Db::table('access_delegations')->insertGetId([
72	            'grantor_id'  => $grantor['id'],
73	            'grantee_id'  => $granteeId,
74	            'scope_level' => $scopeLevel,
75	            'scope_id'    => $scopeId,
76	            'expires_at'  => date('Y-m-d H:i:s', $expiresTs),
77	            'status'      => 'pending_approval',
78	            'approved_by' => null,
79	        ]);
80	
81	        LogService::info('delegation_created', ['delegation_id' => $id, 'grantor_id' => $grantor['id'], 'grantee_id' => $granteeId], $traceId);
82	
83	        AuditService::log(
84	            'delegation_created',
85	            (int)$grantor['id'],
86	            'access_delegation',
87	            (int)$id,
88	            null,
89	            ['grantee_id' => $granteeId, 'scope_level' => $scopeLevel, 'scope_id' => $scopeId, 'status' => 'pending_approval'],
90	            $ip ?: RequestContext::ip(),
91	            RequestContext::device(),
92	            $traceId
93	        );
94	
95	        return ['delegation_id' => $id, 'status' => 'pending_approval'];
96	    }
97	
98	    /**
99	     * Approve (or reject) a pending delegation.
100	     * Two-person rule: approver must be a different system_admin than the grantor.
101	     * @throws \think\exception\HttpException
102	     */
103	    public static function approve(int $delegationId, bool $approve, array $approver, ?string $reason = null, string $traceId = '', string $ip = ''): array
104	    {
105	        if ($approver['role'] !== 'system_admin') {
106	            throw new \think\exception\HttpException(403, 'Only system_admin may approve delegations');
107	        }
108	
109	        $delegation = Db::table('access_delegations')->where('id', $delegationId)->find();
110	        if (!$delegation) throw new \think\exception\HttpException(404, 'Delegation not found');
111	
112	        if ($delegation['status'] !== 'pending_approval') {
113	            throw new \think\exception\HttpException(409, "Delegation is not pending (current: {$delegation['status']})");
114	        }
115	
116	        // Two-person rule: approver must differ from grantor
117	        if ((int)$delegation['grantor_id'] === (int)$approver['id']) {
118	            throw new \think\exception\HttpException(403, 'Two-person rule: grantor cannot approve their own delegation');
119	        }
120	
121	        $newStatus = $approve ? 'active' : 'revoked';
122	        $before = ['status' => $delegation['status'], 'approved_by' => $delegation['approved_by']];
123	
124	        Db::table('access_delegations')->where('id', $delegationId)->update([
125	            'status'      => $newStatus,
126	            'approved_by' => $approver['id'],
127	        ]);
128	
129	        LogService::info('delegation_decision', [
130	            'delegation_id' => $delegationId, 'approver_id' => $approver['id'], 'decision' => $newStatus,
131	        ], $traceId);
132	
133	        AuditService::log(
134	            'delegation_' . ($approve ? 'approved' : 'rejected'),
135	            (int)$approver['id'],
136	            'access_delegation',
137	            $delegationId,
138	            $before,
139	            ['status' => $newStatus, 'approved_by' => $approver['id'], 'reason' => $reason],
140	            $ip ?: RequestContext::ip(),
141	            RequestContext::device(),
142	            $traceId
143	        );
144	
145	        return ['delegation_id' => $delegationId, 'status' => $newStatus];
146	    }
147	
148	    public static function list(array $filters = []): array
149	    {
150	        $query = Db::table('access_delegations');
151	        if (!empty($filters['status'])) $query->where('status', $filters['status']);
152	
153	        $page = max((int)($filters['page'] ?? 1), 1);
154	        $size = min(max((int)($filters['size'] ?? 20), 1), 100);
155	        $total = $query->count();
156	        $items = $query->order('created_at', 'desc')->limit(($page - 1) * $size, $size)->select()->toArray();
157	
158	        return ['items' => $items, 'page' => $page, 'total' => $total];
159	    }
160	}
